import React from "react";
import icon1 from "../icon1.png";
import icon2 from "../icon2.png";
import Chip from "@material-ui/core/Chip";

function firstPage(props) {
  return (
    <div className={"firstPage"} id="page1">
      <div className={"gridItem"} style={{ height: props.height / 2 }}>
        <p className={"title"}>My Knowledge</p>
        <p className={"textArea"}>
          Hi, my name is Michal and I am a Javascript and Typesript developer. I
          have solid skills in many frameworks, like Angular, React , React
          Native or Ionic. I have expirience in cross platform mobile and web
          Apps Development.
        </p>
      </div>
      <div className={"gridItemImg1"} style={{ height: props.height / 2 }}>
        <img alt={"icon1"} className={"icon1"} src={icon1} />
      </div>
      <div className={"gridItemImg"} style={{ height: props.height / 2 }}>
        <img alt={"icon2"} className={"icon2"} src={icon2} />
      </div>
      <div className={"gridItem"} style={{ height: props.height / 2 }}>
        <p className={"title"}>Web Development Skills</p>
        <Chip className={"chip"} label="HTML" color="primary" />
        <Chip className={"chip"} label="CSS" />
        <Chip className={"chip"} label="HTML" />
        <Chip className={"chip"} label="JavaScript" />
        <Chip className={"chip"} label="TypeScript" />
        <Chip className={"chip"} label="Node.js" />
        <Chip className={"chip"} label="npm" />
        <Chip className={"chip"} label="Responsive Design" />
        <Chip
          className={"chip"}
          label="Angular"
          color="secondary"
          style={{ backgroundColor: "#631cbd" }}
        />
        <Chip className={"chip"} label="React" color="secondary" />
        <Chip className={"chip"} label="Front-End Development" />
        <Chip className={"chip"} label="Back-End Development" />
        <Chip className={"chip"} label="CMS" />
        <Chip className={"chip"} label="Wordpress" />
        <p className={"title"}>Mobile Apps Development</p>
        <Chip className={"chip"} label="React-Native" color="secondary" />
        <Chip className={"chip"} label="Ionic" />
        <Chip className={"chip"} label="Cordova" />
        <Chip className={"chip"} label="Android Studio" />
        <Chip className={"chip"} label="Android" />
        <Chip className={"chip"} label="Hybrid Apps" color="secondary" />
        <Chip className={"chip"} label="Multi-Touch Gestures" />
        <Chip className={"chip"} label="TV Apps Development" />
        <p className={"title"}>Computer programming</p>
        <Chip className={"chip"} label="Visual Studio" color="secondary" />
        <Chip className={"chip"} label="C#" />
        <Chip className={"chip"} label="Java" />
        <Chip className={"chip"} label="C++" />
        <Chip className={"chip"} label="SQL" />
        <Chip className={"chip"} label="Databases" color="secondary" />
        <Chip className={"chip"} label="Data Visualization" />
        <Chip className={"chip"} label="Git" />
        <Chip className={"chip"} label="Subversion" />
        <Chip className={"chip"} label="Open GL" />
      </div>
    </div>
  );
}

export default firstPage;
