import React, { useEffect, useState } from "react";
import box2 from "../box2.jpg";
import box5 from "../box5.jpg";
import box4 from "../box4.jpg";

function Banner() {
  const [_index, setIndex] = useState(0);
  const __height = window.innerHeight;

  useEffect(() => {
    const timer = setInterval(() => {
      if (_index === 2) {
        setIndex(0);
      } else {
        setIndex(_index + 1);
      }
    }, 2000);
    return () => clearInterval(timer);
  }, [_index]);

  const items = [
    { src: box2, text: "My Education", id: "#page2" },
    { src: box4, text: "My Projects", id: "#page3" },
    { src: box5, text: "My Knowledge", id: "#page1" },
  ];

  const _items = items.map((item, index) => {
    const _height = __height / 2;
    return index === _index ? (
      <div
        index={index}
        style={{
          width: "100%",
          height: _height,
          margin: 5,
          textAlign: "center",
        }}
        className={"box"}
      >
        <a href={item.id}>
          <p className={"boxText"}>{item.text}</p>
        </a>

        <img style={{ width: "100%", height: "100%" }} src={item.src} />
      </div>
    ) : null;
  });
  return <div className={"boxCont"}>{_items}</div>;
}
export default Banner;
